const body = $input.item.json.body || {};
const id = String(body.auction_id || '').trim();
const handle = String(body.handle || body.email || body.name || '').trim().slice(0, 120);
const pi = String(body.payment_intent_id || '').trim();
if (!id) return { json: { ok: false, status: 400, error: 'auction_id required' } };
if (!handle) return { json: { ok: false, status: 400, error: 'name or email required' } };
if (!pi) return { json: { ok: false, status: 400, error: 'payment_intent_id required' } };
return { json: { auction_id: id, handle: handle, payment_intent_id: pi } };

const s = $input.item.json || {};
const x = $('Extract').item.json;
if (s.error) return { json: { ok: false, status: 502, error: 'Stripe: ' + (s.error.message || 'lookup failed') } };
if (!s.id) return { json: { ok: false, status: 400, error: 'Payment not found' } };
if (s.status !== 'succeeded') return { json: { ok: false, status: 402, error: 'Payment did not complete (status: ' + s.status + ')' } };
const meta = s.metadata || {};
if (String(meta.auction_id || '') !== x.auction_id) return { json: { ok: false, status: 400, error: 'Payment does not match this item' } };
if (meta.kind !== 'luxi_buynow') return { json: { ok: false, status: 400, error: 'Payment is not a Buy Now charge' } };
return { json: { ok: true, auction_id: x.auction_id, handle: x.handle, amount_cents: parseInt(s.amount, 10) } };

let r = $input.item.json; if (Array.isArray(r)) r = r[0] || {};
const v = $('Verify Paid').item.json;
if (r == null || typeof r !== 'object') r = { ok: false };
if (!r.ok) {
  // Payment succeeded but the sale record failed — surface clearly so it can be reconciled (do NOT tell the buyer it failed; they were charged).
  return { json: { ok: true, status: 200, paid: true, recorded: false, amount_display: '$' + ((v.amount_cents||0)/100).toFixed(2), warning: (r.error || 'sale record pending') } };
}
return { json: { ok: true, status: 200, paid: true, recorded: true, amount_display: '$' + ((v.amount_cents||0)/100).toFixed(2) } };
